import { Module } from '@nestjs/common';
import { TypeOrmModule } from '@nestjs/typeorm';
import { AvaliacaoEntity } from './entities/avaliacao.entity';
import { AvaliacoesService } from './avaliacoes.service';
import { AvaliacoesController } from './avaliacoes.controller';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { APP_GUARD } from '@nestjs/core';

@Module({
  imports: [TypeOrmModule.forFeature([AvaliacaoEntity])],
  providers: [
    AvaliacoesService,
    {
      provide: APP_GUARD,
      useClass: JwtAuthGuard
    }
  ],
  controllers: [AvaliacoesController],
  exports: [AvaliacoesService]
})
export class AvaliacoesModule {}

import { Entity, Column, PrimaryGeneratedColumn, ManyToOne, Index, CreateDateColumn } from 'typeorm';
import { UserEntity } from '../../users/entities/user.entity';
import { PhraseEntity } from '../../phrases/entities/phrase.entity';
import * as crypto from 'crypto';

@Entity('avaliacoes')
@Index(['user', 'phrase'], { unique: true })
export class AvaliacaoEntity {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column('float')
  nota: number;

  @ManyToOne(() => UserEntity, user => user.avaliacoes, { eager: false, nullable: false })
  user: UserEntity;

  @ManyToOne(() => PhraseEntity, phrase => phrase.avaliacoes, { eager: false, nullable: false })
  phrase: PhraseEntity;

  @CreateDateColumn()
  createdAt: Date;

  @Column({ type: 'bytea', nullable: true })
  encryptedData?: Buffer;

  setEncryptedData(plainData: string, encryptionKey: string) {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-cbc', Buffer.from(encryptionKey, 'hex'), iv);
    let encrypted = cipher.update(plainData);
    encrypted = Buffer.concat([encrypted, cipher.final()]);
    this.encryptedData = Buffer.concat([iv, encrypted]);
  }

  getDecryptedData(encryptionKey: string): string | null {
    if (!this.encryptedData) return null;
    const iv = this.encryptedData.slice(0, 16);
    const encryptedText = this.encryptedData.slice(16);
    const decipher = crypto.createDecipheriv('aes-256-cbc', Buffer.from(encryptionKey, 'hex'), iv);
    let decrypted = decipher.update(encryptedText);
    decrypted = Buffer.concat([decrypted, decipher.final()]);
    return decrypted.toString();
  }
}

import { IsNumber, Min, Max, IsUUID } from 'class-validator';

export class CreateAvaliacaoDto {
  @IsUUID()
  phraseId: string;

  @IsNumber({ maxDecimalPlaces: 1 })
  @Min(0)
  @Max(5)
  nota: number;
}

import { Injectable, Logger, BadRequestException, ConflictException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { CreateAvaliacaoDto } from './dto/create-avaliacao.dto';
import { AvaliacaoEntity } from './entities/avaliacao.entity';
import { UserEntity } from '../users/entities/user.entity';

@Injectable()
export class AvaliacoesService {
  private readonly logger = new Logger(AvaliacoesService.name);
  private readonly ENCRYPTION_KEY = process.env.AVALIACAO_ENCRYPTION_KEY || '';

  constructor(
    @InjectRepository(AvaliacaoEntity)
    private readonly avaliacaoRepo: Repository<AvaliacaoEntity>,
  ) {
    if (!this.ENCRYPTION_KEY || this.ENCRYPTION_KEY.length !== 64) {
      this.logger.error('Chave de criptografia inválida ou não configurada (deve ser hex 32 bytes)');
      throw new Error('Chave de criptografia inválida ou não configurada');
    }
  }

  /**
   * Cria uma avaliação para uma frase pelo usuário autenticado
   * @param user Usuário autenticado
   * @param dto Dados da avaliação
   * @returns Avaliação criada
   * @throws BadRequestException para nota inválida
   * @throws ConflictException se avaliação já existe para user+phrase
   */
  async criarAvaliacao(user: UserEntity, dto: CreateAvaliacaoDto): Promise<AvaliacaoEntity> {
    this.logger.log({ message: 'Criando avaliação', userId: user.id, phraseId: dto.phraseId });

    if (dto.nota < 0 || dto.nota > 5) {
      throw new BadRequestException('Nota deve ser entre 0 e 5');
    }

    const existing = await this.avaliacaoRepo.findOne({ where: { user: { id: user.id }, phrase: { id: dto.phraseId } } });
    if (existing) {
      throw new ConflictException('Usuário já avaliou esta frase');
    }

    const avaliacao = this.avaliacaoRepo.create({
      nota: dto.nota,
      user,
      phrase: { id: dto.phraseId } as any,
    });

    // Criptografar dados sensíveis se houver (exemplo placeholder)
    // avaliacao.setEncryptedData(JSON.stringify({ nota: dto.nota }), this.ENCRYPTION_KEY);

    await this.avaliacaoRepo.save(avaliacao);
    this.logger.log({ message: 'Avaliação criada com sucesso', avaliacaoId: avaliacao.id });
    return avaliacao;
  }
}

import { Controller, Post, Body, UseGuards, Req, HttpCode, HttpStatus } from '@nestjs/common';
import { AvaliacoesService } from './avaliacoes.service';
import { CreateAvaliacaoDto } from './dto/create-avaliacao.dto';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { Request } from 'express';

@Controller('avaliacoes')
export class AvaliacoesController {
  constructor(private readonly avaliacoesService: AvaliacoesService) {}

  @UseGuards(JwtAuthGuard)
  @Post()
  @HttpCode(HttpStatus.CREATED)
  async criarAvaliacao(@Req() req: Request, @Body() dto: CreateAvaliacaoDto) {
    const user = req.user;
    const avaliacao = await this.avaliacoesService.criarAvaliacao(user, dto);
    return { message: 'Avaliação submetida com sucesso', avaliacaoId: avaliacao.id };
  }
}

import React, { useState } from 'react';
import axios from 'axios';

interface AvaliacaoNotaProps {
  phraseId: string;
  onSuccess?: () => void;
}

const AvaliacaoNota: React.FC<AvaliacaoNotaProps> = ({ phraseId, onSuccess }) => {
  const [nota, setNota] = useState<number | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  const handleSubmit = async () => {
    if (nota === null || nota < 0 || nota > 5) {
      setError('Por favor, selecione uma nota entre 0 e 5');
      return;
    }
    setLoading(true);
    setError(null);
    setSuccess(null);
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Você precisa estar autenticado para enviar avaliação');
        setLoading(false);
        return;
      }
      await axios.post('/api/avaliacoes', { phraseId, nota }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setSuccess('Avaliação enviada com sucesso');
      setNota(null);
      if (onSuccess) onSuccess();
    } catch (err: any) {
      if (err.response?.data?.message) {
        setError(err.response.data.message);
      } else {
        setError('Erro ao enviar avaliação');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div aria-live="polite" role="region" className="avaliacao-nota">
      <label htmlFor="nota" className="block font-semibold mb-1">Avalie esta frase (0 a 5):</label>
      <input
        id="nota"
        type="number"
        step="0.1"
        min="0"
        max="5"
        value={nota !== null ? nota : ''}
        onChange={e => setNota(parseFloat(e.target.value))}
        aria-describedby="notaHelp"
        disabled={loading}
        className="border rounded px-2 py-1 w-20"
      />
      <button
        onClick={handleSubmit}
        disabled={loading || nota === null}
        className="ml-2 bg-blue-600 text-white px-3 py-1 rounded disabled:opacity-50"
      >
        {loading ? 'Enviando...' : 'Enviar'}
      </button>
      <p id="notaHelp" className="sr-only">Nota decimal entre zero e cinco</p>
      {error && <p role="alert" className="text-red-600 mt-2">{error}</p>}
      {success && <p role="status" className="text-green-600 mt-2">{success}</p>}
    </div>
  );
};

export default AvaliacaoNota;

